#!/usr/bin/env node
/**
 * IVX Credential End-to-End Audit + Deploy Finisher
 * 
 * 1. Sign in as owner via Supabase password auth
 * 2. Check deployment credential status (GITHUB_TOKEN, RENDER_API_KEY, etc.)
 * 3. Sync credentials from project store to encrypted store
 * 4. Check GitHub token validity
 * 5. Try GitHub sync (push latest to GitHub mirror)
 * 6. Try Render self-deploy
 * 7. Try Render auto-deploy fix (updates source + triggers deploy)
 * 8. Poll /version until production matches target commit
 * 9. Verify agent-audit endpoint
 */

const SUPABASE_URL = 'https://kvclcdjmjghndxsngfzb.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzMxOTQwMjcsImV4cCI6MjA4ODc3MDAyN30.OLDwa21VHQNs151AD-8k--_HigQ2d-N7yJfFn5UeNPk';
const OWNER_EMAIL = 'iperez4242@gmail.com';
const OWNER_PASSWORD = 'X146corp@1x146corp$$1';
const API_BASE = 'https://api.ivxholding.com';
const RORK_ROUTER_URL = 'https://rork-git-router.rork-direct.workers.dev/git/j2l8t44588ix9ns7b57mu';
const GITHUB_REPO = 'ibb142/rork-global-real-estate-invest';

function log(step, msg, data) {
  const ts = new Date().toISOString();
  const prefix = `[${ts}] [${step}]`;
  if (data !== undefined) {
    console.log(prefix, msg, JSON.stringify(data).slice(0, 600));
  } else {
    console.log(prefix, msg);
  }
}

async function signIn() {
  log('1', 'Signing in as owner via Supabase password auth...');
  const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
    method: 'POST',
    headers: { apikey: SUPABASE_ANON_KEY, Authorization: `Bearer ${SUPABASE_ANON_KEY}` },
    body: JSON.stringify({ email: OWNER_EMAIL, password: OWNER_PASSWORD }),
  });
  const text = await res.text();
  const json = text ? JSON.parse(text) : null;
  if (!res.ok || !json?.access_token) {
    throw new Error(`Sign-in failed: ${res.status} ${json?.error_description || json?.message || text}`);
  }
  log('1', 'Owner signed in successfully', {
    userId: json.user?.id,
    email: json.user?.email,
    role: json.user?.role || json.user?.app_metadata?.role,
  });
  return json.access_token;
}

async function apiCall(token, method, path, body) {
  const headers = { 'Content-Type': 'application/json' };
  if (token) headers.Authorization = `Bearer ${token}`;
  const res = await fetch(`${API_BASE}${path}`, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined,
  });
  const text = await res.text();
  let json = null;
  try { json = text ? JSON.parse(text) : null; } catch { /* not json */ }
  return { status: res.status, json, text, ok: res.ok };
}

async function checkDeploymentStatus(token) {
  log('2', 'Checking deployment credential status...');
  const r = await apiCall(token, 'GET', '/api/ivx/owner-variables/deployment-status');
  log('2', 'Deployment status response', { status: r.status, body: r.json });
  return r;
}

async function syncFromProjectStore(token) {
  log('3', 'Syncing credentials from project store to encrypted store...');
  const r = await apiCall(token, 'POST', '/api/ivx/owner-variables/sync-from-project-store', {});
  log('3', 'Sync response', { status: r.status, body: r.json });
  return r;
}

async function checkGithubRepoHead() {
  log('4', `Checking GitHub repo ${GITHUB_REPO} HEAD via public API...`);
  // Try without token first (in case repo is public)
  const res = await fetch(`https://api.github.com/repos/${GITHUB_REPO}/git/ref/heads/main`, {
    headers: { Accept: 'application/vnd.github+json' },
  });
  const text = await res.text();
  let json = null;
  try { json = text ? JSON.parse(text) : null; } catch {}
  log('4', 'GitHub API response (no auth)', { status: res.status, sha: json?.object?.sha || null });
  return { status: res.status, json, ok: res.ok };
}

async function tryGithubSync(token, apply) {
  const mode = apply ? 'APPLY' : 'DRY-RUN';
  log('5', `GitHub sync (${mode})...`);
  const r = await apiCall(token, 'POST', '/api/ivx/autonomy/github/sync', {
    apply,
    message: `deploy: agent audit upgrade — all 12 agents to senior (${mode})`,
    timeoutMs: 300000,
  });
  log('5', `GitHub sync ${mode} response`, { status: r.status, body: r.json });
  return r;
}

async function trySelfDeploy() {
  log('6', 'Triggering Render self-deploy (POST /api/ivx/deploy, no auth needed)...');
  const r = await apiCall(null, 'POST', '/api/ivx/deploy', {});
  log('6', 'Self-deploy response', { status: r.status, body: r.json });
  return r;
}

async function tryRenderAutoDeployFix() {
  log('7', 'Triggering Render auto-deploy fix (updates source + deploys)...');
  const r = await apiCall(null, 'POST', '/api/ivx/render-auto-deploy/fix', {
    confirm: 'FIX_IVX_RENDER_AUTO_DEPLOY',
  });
  log('7', 'Render auto-deploy fix response', { status: r.status, body: r.json });
  return r;
}

async function checkVersion() {
  const r = await apiCall(null, 'GET', '/version');
  log('VERSION', 'Current production version', { status: r.status, body: r.json });
  return r;
}

async function checkAgentAudit(token) {
  log('AUDIT', 'Checking agent-audit overview endpoint...');
  const r = await apiCall(token, 'GET', '/api/ivx/agent-audit/overview');
  log('AUDIT', 'Agent audit response', { status: r.status, body: r.json });
  return r;
}

async function checkRuntimeVariables(token) {
  log('RUNTIME', 'Checking runtime variables...');
  const r = await apiCall(token, 'GET', '/api/ivx/runtime-variables');
  log('RUNTIME', 'Runtime variables', { status: r.status, body: r.json });
  return r;
}

async function main() {
  // Step 0: Check current production version
  await checkVersion();

  // Step 1: Sign in
  const token = await signIn();

  // Step 2: Check deployment credential status
  await checkDeploymentStatus(token);

  // Step 3: Sync credentials from project store
  await syncFromProjectStore(token);

  // Step 3b: Re-check deployment status after sync
  await checkDeploymentStatus(token);

  // Step 3c: Check runtime variables
  await checkRuntimeVariables(token);

  // Step 4: Check GitHub repo HEAD
  await checkGithubRepoHead();

  // Step 5: Try GitHub sync (dry-run first)
  const dryRun = await tryGithubSync(token, false);

  if (dryRun.ok || (dryRun.json?.syncStatus === 'already_up_to_date')) {
    log('5', 'Dry-run passed, attempting APPLY sync...');
    const applyResult = await tryGithubSync(token, true);
    if (applyResult.json?.syncStatus === 'pushed' || applyResult.json?.pushedCommit) {
      log('5', 'GitHub push successful! Render should auto-deploy.');
    }
  } else if (dryRun.json?.verificationProof?.scriptStderrTail?.includes('401')) {
    log('5', 'GitHub token is INVALID (401). Need to fix token.');
  }

  // Step 6: Try self-deploy (works if GitHub repo has latest code)
  await trySelfDeploy();

  // Step 7: Try render auto-deploy fix
  await tryRenderAutoDeployFix();

  // Step 8: Poll version for up to 5 minutes
  log('8', 'Polling /version for 5 minutes...');
  for (let i = 0; i < 30; i++) {
    await new Promise((resolve) => setTimeout(resolve, 10000));
    const v = await checkVersion();
    if (v.json?.commitSha?.slice(0, 7) === 'd9ddf03' || v.json?.gitSha?.slice(0, 7) === 'd9ddf03') {
      log('8', 'Production is now running target commit!');
      break;
    }
  }

  // Step 9: Verify agent-audit endpoint
  await checkAgentAudit(token);

  // Final version check
  await checkVersion();

  log('DONE', 'Credential audit + deploy orchestration complete');
}

main().catch((e) => {
  console.error('FATAL:', e.message);
  process.exit(1);
});

